schema AgentStep:
    thought: str
    tool:    optional {name: str, args: dict}
    answer:  optional str

schema  = StructuredSchema(AgentStep)
limiter = TokenBucket(rate_per_sec=20)

function business_service__step(history):
    limiter.acquire()
    prompt = render_agent_prompt(history, tools=TOOL_REGISTRY)
    for attempt in range(3):
        reply = http.post(LLM_URL + "/generate", body={
            "prompt": prompt, "params": {"max_tokens": 400},
            "schema_hint": schema.to_json_schema()})
        try:
            parsed = parse_and_validate(reply.text, schema); break
        except ParseError as e:
            prompt += "\nLast reply failed: " + str(e) + "\nReturn valid JSON."
    else:
        raise ExhaustedRetries()
    if parsed.tool:
        result = TOOL_REGISTRY[parsed.tool.name](**parsed.tool.args)
        return business_service__step(history + [parsed, result])
    return parsed.answer

