function feature_pipeline(raw_docs):
    for d in raw_docs:
        for ch in split(normalise(d)):
            feature_store.upsert(FeatureRecord(
                schema_version="feat.v4", doc_id=d.id, chunk_id=uuid(),
                text=ch.text, embed_model=EMBED_MODEL,
                embedding=embed(ch.text, model=EMBED_MODEL)))

function answer(query):
    schema   = StructuredSchema(RagAnswer)
    artifact = model_registry.load_latest("qa-tuned")
    docs     = feature_store.search(query, k=5)
    for d in docs:
        if d.schema_version != artifact.expected_feat_ver: raise FeatureDrift()
        if d.embed_model    != artifact.expected_embed_model: raise EmbedDrift()
    reply = artifact.generate(prompt=render(query, docs),
                               schema_hint=schema.to_json_schema())
    return parse_and_validate(reply.text, schema)

# Why this works: version metadata on both integration surfaces makes drift
# fail loudly at request time, not silently in answers.
# Related: see `business-llm-microservice-split`, `cdc-vector-sync`.

schema FeatureRecord:
    doc_id: str; chunk_id: str; text: str
    embedding: list[float]; op: str        # "upsert" | "delete"

schema RagAnswer:
