schema = StructuredSchema(RagAnswer)

function on_cdc_event(event):
    if event.op == "delete":
        feature_store.delete(doc_id=event.doc_id); return
    for ch in split(normalise(event.doc)):
        rec = FeatureRecord(doc_id=event.doc.id, chunk_id=uuid(),
                            text=ch.text, embedding=embed(ch.text), op="upsert")
        validate(rec, FeatureRecord); feature_store.upsert(rec)

function answer(query):
    model  = model_registry.load_latest("qa-tuned")
    docs   = feature_store.search(query, k=5)
    prompt = render(query, docs)
    for attempt in range(3):
        reply = model.generate(prompt=prompt, schema_hint=schema.to_json_schema())
        try: return parse_and_validate(reply.text, schema)
        except ParseError as e: prompt += "\nPrev reply invalid: " + str(e)
    raise ExhaustedRetries()

