# Core: deterministic state machine + append-only event store.
# LLM: stateless edge transformers only.

schema TypedEvent:
    kind: enum { user_answer, user_question, system_advance, ... }
    payload: any           # validated per kind
    observed_at: timestamp

function core_apply(state, event):
    # Pure function: (state, event) -> state'
    # Property-tested. No LLM call inside.
    require(safety_check(state, event))
    return transition_table[event.kind](state, event)

function handle_user_text(text):
    # EDGE IN: LLM interprets free-text -> typed event.
    event = llm_edge_in(text, schema=TypedEvent)
    require(event.kind in known_kinds)
    event_store.append(event)
    state = replay(event_store)              # deterministic
    return state

function synthesize_reply(state):
    # EDGE OUT: LLM synthesises user-facing text from typed state.
    return llm_edge_out(state, schema=UserMessage)

# Top-level loop is deterministic. LLM cannot move state on its own.
function turn(user_text):
    state = handle_user_text(user_text)
    return synthesize_reply(state)

from dataclasses import dataclass, field
from typing import Literal, Any
import json, time

EventKind = Literal["user_answer", "user_question", "system_advance"]

@dataclass
class TypedEvent:
    kind: EventKind
    payload: dict
    observed_at: float

@dataclass
class State:
    step: int = 0
    answers: list = field(default_factory=list)
    crisis_flag: bool = False

class EventStore:
    def __init__(self, path: str):
        self.path = path
    def append(self, ev: TypedEvent) -> None:
        with open(self.path, "a") as f:
            f.write(json.dumps(ev.__dict__) + "\n")
    def replay(self) -> list[TypedEvent]:
        out = []
        try:
            with open(self.path) as f:
                for line in f:
                    out.append(TypedEvent(**json.loads(line)))
        except FileNotFoundError:
            pass
        return out

# Deterministic core. Property-tested. No LLM call inside.
def apply_event(state: State, ev: TypedEvent) -> State:
    if ev.kind == "user_answer":
        state.answers.append(ev.payload)
        if looks_like_crisis(ev.payload):  # explicit code rule
            state.crisis_flag = True
    elif ev.kind == "system_advance" and not state.crisis_flag:
        state.step += 1
    return state

def replay_state(store: EventStore) -> State:
    s = State()
    for ev in store.replay():
        s = apply_event(s, ev)
    return s

# LLM edges - stateless, typed in / typed out.
def llm_edge_in(text: str) -> TypedEvent:
    # Call your LLM with a strict structured-output schema here.
    parsed = call_llm_structured(
        prompt=f"Classify into a TypedEvent: {text}",
        schema={"kind": EventKind, "payload": dict},
    )
    return TypedEvent(kind=parsed["kind"],
                      payload=parsed["payload"],
                      observed_at=time.time())

def llm_edge_out(state: State) -> str:
    return call_llm_structured(
        prompt=f"Compose next question from state: {state}",
        schema={"text": str},
    )["text"]

def turn(store: EventStore, user_text: str) -> str:
    ev = llm_edge_in(user_text)
    store.append(ev)
    state = replay_state(store)
    return llm_edge_out(state)

schema Record:
    schema_version: str          # "record.v2"
    id: str; supplier: str; lead_time_days: int
    material_type: enum { yarn, fabric, trim }
    yarn:    optional YarnExt
    fabric:  optional FabricExt
    trim:    optional TrimExt

schema YarnExt:   { weight: float, fibre: str }
schema FabricExt: { width_cm: float, weave: str }
schema TrimExt:   { attachment: str }

function parse_record(raw) -> ParsedRecord:
    schema = StructuredSchema(Record, version="record.v2")
    core   = parse_and_validate(raw, schema, allow_partial=True)
    populated = [k for k in ["yarn", "fabric", "trim"] if core[k] is not None]
    if populated != [core.material_type]:
        return ParsedRecord(core=core, ext=None,
                            errors=["discriminator/extension mismatch"])
    ext_cls = {"yarn": YarnExt, "fabric": FabricExt, "trim": TrimExt}[core.material_type]
    try:
        ext = parse_and_validate(core[core.material_type], StructuredSchema(ext_cls))
        return ParsedRecord(core=core, ext=ext, errors=[])
    except ParseError as e:
        return ParsedRecord(core=core, ext=None, errors=[str(e)])

# Why this works: splitting core and extension validation lets a malformed
# sub-type degrade gracefully; the cross-check catches silent producer bugs.
# Related: see `schema-extensibility`, `translation-layer`.

schema Envelope:
    schema_version: str           # "env.v1"
    type: str; payload: object
    extensions: map<str, any>?

schema Record:
    id: str; supplier: str
    material_type: enum { yarn, fabric, trim }

schema YarnExt:   { weight: float, fibre: str }
schema FabricExt: { width_cm: float, weave: str }

function write(record, sub_ext):
    validate(record, StructuredSchema(Record))
    return Envelope(schema_version="env.v1", type="material-record",
                    payload=record,
                    extensions={ "x-mat." + record.material_type: sub_ext })

function read(envelope):
    core    = parse_and_validate(envelope.payload, StructuredSchema(Record))
    key     = "x-mat." + core.material_type
    ext_raw = (envelope.extensions or {}).get(key)
    ext_cls = {"yarn": YarnExt, "fabric": FabricExt}.get(core.material_type)
    if ext_raw is None or ext_cls is None:
        return CoreView(core, ext=ext_raw)              # opaque round-trip
    return FullView(core, parse_and_validate(ext_raw, StructuredSchema(ext_cls)))

# Why this works: reserved-namespace extensions let new sub-types ship
# without bumping schema_version, while old clients still round-trip safely.
# Related: see `schema-extensibility`, `translation-layer`.

template_registry = {
    "onboarding-qa": {
        version: "qa.v4",
        frame: "Answer using ONLY the policy text. JSON only.",
        few_shot: [...],
        output_schema: AnswerWithCitation,
    },
}
failure_window = SlidingWindow(minutes=15)

function handle(user_input, task_id):
    tpl    = template_registry[task_id]
    schema = StructuredSchema(tpl.output_schema, version=tpl.version)
    prompt = tpl.frame + restate_goal(user_input) \
           + render_few_shot(tpl.few_shot) + "\nUser: " + user_input
    for attempt in range(2):
        raw = llm.generate(prompt, schema_hint=schema.to_json_schema())
        try:
            shaped = parse_and_validate(raw, schema)
            failure_window.record_success(task_id); return shaped
        except ParseError as e:
            prompt += "\nFailed schema (" + str(e) + "). Return ONLY valid JSON."
    failure_window.record_failure(task_id, schema_version=tpl.version)
    if failure_window.rate(task_id) > 0.1:
        alert("template drift", task_id=task_id, schema_version=tpl.version)
    raise ParseError("optimiser exhausted retries")

# Why this works: pinning schema_version per template makes drift observable;
# one tightened retry absorbs most parse failures without re-rendering.
# Related: see `prompt-versioning`, `structured-output`.

schema Envelope:
    schema_version: str            # "env.v2"
    type: str; payload: object
    extensions: map<str, any>?

schema EventCore:
    event_type: enum { order_placed, order_shipped, order_cancelled }
    order_id: str; ts: str

schema OrderPlacedExt:    { sku: str, qty: int, price: float }
schema OrderShippedExt:   { carrier: str, tracking: str }
schema OrderCancelledExt: { reason: str }

EXT_BY_TYPE = {"order_placed": OrderPlacedExt,
                "order_shipped": OrderShippedExt,
                "order_cancelled": OrderCancelledExt}

function read(env):
    if major(env.schema_version) > MAX_KNOWN_MAJOR:
        raise IncompatibleSchemaError(env.schema_version)
    core    = parse_and_validate(env.payload, StructuredSchema(EventCore))
    ext_cls = EXT_BY_TYPE.get(core.event_type)
    ext_raw = (env.extensions or {}).get("x-order." + core.event_type)
    if ext_cls is None or ext_raw is None:
        return CoreOnlyView(core, opaque=ext_raw)
    return FullView(core, parse_and_validate(ext_raw, StructuredSchema(ext_cls)))

# Why this works: nesting a polymorphic record inside the versioned envelope
# lets new sub-types ship as new x-order.* extensions without a major bump.
# Related: see `polymorphic-record`, `translation-layer`.

function generate_typed(prompt, schema, max_retries=2):
    last_error = null
    for attempt in 1..max_retries+1:
        raw = llm.generate(
            prompt=prompt,
            response_format=schema,        # provider constrained-decoding
            repair_hint=last_error,        # null on first attempt
        )
        try:
            return schema.validate(raw)    # typed object
        except ValidationError as e:
            last_error = e.message         # feed back to next attempt

    raise SchemaError("output did not validate after retries")

