# ---- normalized contract the core speaks (no channel knowledge) ----
@dataclass
class Inbound:  session_id: str; text: str; modality: str; attachments: list
@dataclass
class Outbound: text: str; effects: list = (); handoff: bool = False

# ---- the agent core: reasoning, tools, policy written ONCE ----
def agent_core(ev: Inbound, store) -> Outbound:
    state = store.load(ev.session_id)          # channel-independent session id
    reply, effects = reason_and_act(ev, state)  # same logic on every surface
    store.save(ev.session_id, state)
    return Outbound(text=reply, effects=effects)

# ---- one adapter per channel: ALL channel specifics live here ----
class SlackAdapter(Port):
    def to_event(self, msg):   return Inbound(msg.thread_ts, msg.text, "text", msg.files)
    def from_action(self, a):  slack.post(thread=a.session_id, text=a.text)

class VoiceAdapter(Port):
    def to_event(self, frame): return Inbound(frame.call_id, stt(frame.audio), "voice", [])
    def from_action(self, a):  tts_stream(a.text)   # streaming + barge-in here, not in core

